translated_files.mix_kernels.cl:
#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef class_T
#define class_T float
#endif

inline class_T conv_int_class_T(const int i) {
    return (class_T)(i);
}

inline class_T mad_class_T(const class_T a, const class_T b, const class_T c) {
    return a * b + c;
}

inline int equal_class_T(const class_T a, const class_T b) {
#ifdef ENABLE_HP
    return all(a == b);
#else
    return a == b;
#endif
}

__kernel void benchmark_func(class_T seed, __global class_T *g_data) {
    const uint blockSize = (uint)blockdim;
    const int gid = (int)get_global_id(0);
    const int lid = (int)get_local_id(0);
    const int group = (int)get_group_id(0);

#ifdef BLOCK_STRIDED
    const int stride = (int)blockSize;
    const int idx = group * (int)(blockSize * ELEMENTS_PER_THREAD) + lid;
    const int big_stride = (int)(get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD);
#else
    const int stride = (int)get_global_size(0);
    const int idx = gid;
    const int big_stride = (int)(get_global_size(0) * ELEMENTS_PER_THREAD);
#endif

    class_T tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < FUSION_DEGREE; k++) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = mad_class_T(tmps[j], tmps[j], seed);
            }
        }

        class_T sum = conv_int_class_T(0);
        for (int j = 0; j + 1 < ELEMENTS_PER_THREAD; j += 2) {
            sum = mad_class_T(tmps[j], tmps[j + 1], sum);
        }

#if (ELEMENTS_PER_THREAD & 1)
        sum = sum + tmps[ELEMENTS_PER_THREAD - 1];
#endif

        if (equal_class_T(sum, conv_int_class_T(-1))) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}
